external_knowledge:
- 'captains at the helm' refers to users with the role of 'manager'; 
- 'assigned full control' refers to an active assignment status in 'user_role_assignments' and 'permission_assignments'; 
- 'currently steering the ship' refers to an active assignment status.

sql:
SELECT *
FROM functionality_assignments
WHERE Function_ID = 'F1' AND Assignment_Status = 'active';

SELECT COUNT(*) 
FROM functionalities 
WHERE Function_Status = 'active';
